import numpy as np

def dropout(
    x: np.ndarray,
    p: float,
    training: bool,
    seed: int = None
) -> np.ndarray:
    if not training or p == 0.0:
        return x
    rng = np.random.default_rng(seed)
    mask = (rng.uniform(size=x.shape) >= p).astype(float)
    return x * mask / (1.0 - p)
